	if len(departments) == 0 {
		return make([]map[string]interface{}, 0), nil
	}

	// Validate and map groupByField to actual column name
	var columnName string
	switch groupByField {
	case "department":
		columnName = "u.department"
	case "role":
		columnName = "u.role"
	case "display_name":
		columnName = "u.display_name"
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build placeholders for departments
	placeholders := make([]string, len(departments))
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		args[i] = dept
	}

	// Build SQL with safe column name
	sql := fmt.Sprintf(`
		SELECT
			%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s`, columnName, joinStrings(placeholders, ","), columnName)

	var rows []DepartmentReportRow
	_, err := o.Raw(sql, args...).QueryRows(&rows)
	if err != nil {
		return nil, err
	}

	// Convert to map format
	results := make([]map[string]interface{}, len(rows))
	for i, row := range rows {
		results[i] = map[string]interface{}{
			"group_value":      row.GroupValue,
			"user_count":       row.UserCount,
			"total_activities": row.TotalActivities,
		}
	}

	return results, nil
}

// Helper function to join strings with a separator
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

